INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"disable-selection"', '"Prsnt"', '"vanilla"', '{"demo.css": ".unselectable {\n  user-select: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Disable Selection\r\n    </h1>\r\n    <p>You can select me.</p>\r\n    <p class=\"unselectable\">You can''t select me!</p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/disable-selection"}'), ('"floating-label"', '"Prsnt"', '"vanilla"', '{"demo.css": ".floating-label {\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  position: relative;\n}\n\n.floating-label__input {\n  border: none;\n  padding: 0.5rem;\n  height: 100%;\n}\n\n/*\nShow the label at desired position when the \nplaceholder of input isn''t shown\n*/\n.floating-label__input:not(:placeholder-shown) + .floating-label__label {\n  background: #fff;\n  transform: translate(0, -200%);\n  opacity: 1;\n}\n\n.floating-label__label {\n  /* Position the label */\n  left: 1rem;\n  position: absolute;\n  top: 100%;\n\n  /* Hide it by default */\n  opacity: 0;\n  transition: all 200ms;\n\n  padding: 0 0.5rem;\n}\n\n/* Type something in the input to see how the label is shown up. */\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Floating Label\r\n    </h1>\r\n    <div class=\"floating-label\">\r\n      <!-- The input -->\r\n      <input placeholder=\"Placeholder\" class=\"floating-label__input\" />\r\n\r\n      <!-- The label -->\r\n      <label class=\"floating-label__label\">Placeholder</label>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/floating-label"}'), ('"hamburger-button"', '"Prsnt"', '"vanilla"', '{"demo.css": ".hamburger-menu {\n  display: flex;\n  flex-flow: column wrap;\n  justify-content: space-between;\n  height: 2.5rem;\n  width: 2.5rem;\n  cursor: pointer;\n}\n\n.hamburger-menu .bar {\n  height: 5px;\n  background: black;\n  border-radius: 5px;\n  margin: 3px 0px;\n  transform-origin: left;\n  transition: all 0.5s;\n}\n\n.hamburger-menu:hover .top {\n  transform: rotate(45deg);\n}\n\n.hamburger-menu:hover .middle {\n  opacity: 0;\n}\n\n.hamburger-menu:hover .bottom {\n  transform: rotate(-45deg);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Hamburger Button\r\n    </h1>\r\n    <div class=\"hamburger-menu\">\r\n      <div class=\"bar top\"></div>\r\n      <div class=\"bar middle\"></div>\r\n      <div class=\"bar bottom\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/hamburger-button"}'), ('"input-addon"', '"Prsnt"', '"vanilla"', '{"demo.css": ".input-addon {\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  display: flex;\n}\n\n.input-addon__input {\n  border: none;\n\n  /* Take the remaining width */\n  flex: 1;\n}\n\n.input-addon__addon {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n}\n\n.input-addon__addon--prepended {\n  border-right: 1px solid #d1d5db;\n}\n.input-addon__addon--appended {\n  border-left: 1px solid #d1d5db;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Input addon\r\n    </h1>\r\n    <!-- Add-on prepended -->\r\n    <div class=\"input-addon\">\r\n      <!-- Add-on -->\r\n      <div class=\"input-addon__addon input-addon__addon--prepended\">Add-on</div>\r\n\r\n      <!-- Input -->\r\n      <input type=\"text\" class=\"input-addon__input\" />\r\n    </div>\r\n\r\n    <!-- Add-on appended -->\r\n    <div class=\"input-addon\">\r\n      <!-- Input -->\r\n      <input type=\"text\" class=\"input-addon__input\" />\r\n\r\n      <!-- Add-on -->\r\n      <div class=\"input-addon__addon input-addon__addon--appended\">Add-on</div>\r\n    </div>\r\n\r\n    <!-- Appended and prepended add-ons -->\r\n    <div class=\"input-addon\">\r\n      <!-- Add-on -->\r\n      <div class=\"input-addon__addon input-addon__addon--prepended\">Add-on</div>\r\n\r\n      <!-- Input -->\r\n      <input type=\"text\" class=\"input-addon__input\" />\r\n\r\n      <!-- Add-on -->\r\n      <div class=\"input-addon__addon input-addon__addon--appended\">Add-on</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/input-addon"}'), ('"input-with-prefix"', '"Prsnt"', '"vanilla"', '{"demo.css": ".input-box {\n  display: flex;\n  align-items: center;\n  max-width: 300px;\n  background: #fff;\n  border: 1px solid #a0a0a0;\n  border-radius: 4px;\n  padding-left: 0.5rem;\n  overflow: hidden;\n  font-family: sans-serif;\n}\n\n.input-box .prefix {\n  font-weight: 300;\n  font-size: 14px;\n  color: #999;\n}\n\n.input-box input {\n  flex-grow: 1;\n  font-size: 14px;\n  background: #fff;\n  border: none;\n  outline: none;\n  padding: 0.5rem;\n}\n\n.input-box:focus-within {\n  border-color: #777;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Input With Prefix\r\n    </h1>\r\n    <div class=\"input-box\">\r\n      <span class=\"prefix\">+30</span>\r\n      <input type=\"tel\" placeholder=\"210 123 4567\" />\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/input-with-prefix"}'), ('"popup-menu"', '"Prsnt"', '"vanilla"', '{"demo.css": ".reference {\n  position: relative;\n  background: tomato;\n  width: 100px;\n  height: 80px;\n}\n\n.popout-menu {\n  position: absolute;\n  visibility: hidden;\n  left: 100%;\n  background: #9C27B0;\n  color: white;\n  padding: 16px;\n}\n\n.reference:hover > .popout-menu,\n.reference:focus > .popout-menu,\n.reference:focus-within > .popout-menu {\n  visibility: visible;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Popup Menu\r\n    </h1>\r\n    <div class=\"reference\" tabindex=\"0\">\r\n      <div class=\"popout-menu\">Popout menu</div>\r\n    </div>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/popup-menu"}'), ('"radio-button-group"', '"Prsnt"', '"vanilla"', '{"demo.css": ".radio-button-group {\n  display: flex;\n\n  /* Border */\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  height: 2rem;\n}\n\n.radio-button-group__label {\n  /* Center the content */\n  align-items: center;\n  display: inline-flex;\n\n  border-right: 1px solid #d1d5db;\n  padding: 0.5rem;\n\n  /* For not selected radio */\n  background-color: transparent;\n  color: #ccc;\n}\n\n.radio-button-group__label:last-child {\n  /* Remove the right border from the last label */\n  border-right-color: transparent;\n}\n\n.radio-button-group__label--selected {\n  /* For selected radio */\n  background-color: #3b82f6;\n  color: #fff;\n\n  margin-top: -1px;\n  margin-bottom: -1px;\n}\n\n.radio-button-group__input {\n  /* Hide it */\n  display: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Radio Button Group\r\n    </h1>\r\n    <div class=\"radio-button-group\">\r\n      <!-- Each radio item -->\r\n      <label class=\"radio-button-group__label\">\r\n        <!-- The radio input -->\r\n        <input type=\"radio\" class=\"radio-button-group__input\" />\r\n\r\n        <!-- The text -->\r\n        S\r\n      </label>\r\n\r\n      <!-- Selected item -->\r\n      <label\r\n        class=\"radio-button-group__label radio-button-group__label--selected\"\r\n      >\r\n        M\r\n      </label>\r\n\r\n      <!-- Repeat other items -->\r\n      Repeat Items with label tag.\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/radio-button-group"}'), ('"radio-switch"', '"Prsnt"', '"vanilla"', '{"demo.css": ".radio-switch {\n  background-color: #d1d5db;\n  border-radius: 9999px;\n  display: inline-flex;\n  padding: 0.25rem;\n}\n\n.radio-switch__label {\n  border-radius: 9999px;\n  cursor: pointer;\n  padding: 0.25rem 0.5rem;\n}\n\n.radio-switch__label--selected {\n  /* For selected radio only */\n  background-color: #3b82f6;\n  color: #fff;\n}\n\n.radio-switch__input {\n  display: none;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Radio Switch\r\n    </h1>\r\n    <div class=\"radio-switch\">\r\n      <!-- Radio container -->\r\n      <label class=\"radio-switch__label radio-switch__label--selected\">\r\n        <input type=\"radio\" class=\"radio-switch__input\" />\r\n\r\n        <!-- Text -->\r\n        On\r\n      </label>\r\n\r\n      <!-- Other radio item -->\r\n      Off\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/radio-switch"}'), ('"rating"', '"Prsnt"', '"vanilla"', '{"demo.css": ".rating {\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  flex-direction: row-reverse;\n}\n\n.rating__star:hover,\n.rating__star:hover ~ .rating__star {\n  color: transparent;\n}\n\n/*\nMake all previous stars selected when hover on a star\nNote that we use \\`flex-direction: row-reverse\\` on the container\n*/\n.rating__star:hover:before,\n.rating__star:hover ~ .rating__star:before {\n  color: #eab308;\n  content: \"\u2605\";\n  left: 0;\n  position: absolute;\n}\n\n.rating__star {\n  font-size: 1.5rem;\n\n  /* Reset styles for button */\n  background-color: transparent;\n  border: transparent;\n  margin: 0 2px;\n  padding: 0;\n\n  /* Used to position the hover state */\n  position: relative;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Rating\r\n    </h1>\r\n    <div class=\"rating\">\r\n      <button class=\"rating__star\">\u2606</button>\r\n      <button class=\"rating__star\">\u2606</button>\r\n      <button class=\"rating__star\">\u2606</button>\r\n      <button class=\"rating__star\">\u2606</button>\r\n      <button class=\"rating__star\">\u2605</button>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/rating"}'), ('"search-box"', '"Prsnt"', '"vanilla"', '{"demo.css": ".search-box {\n  display: flex;\n\n  /* If you want to place the icon before the text input */\n  flex-direction: row-reverse;\n\n  /* Border */\n  border: 1px solid #d1d5db;\n}\n\n.search-box__input {\n  border-color: transparent;\n  /* Take available width */\n  flex: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Search Box\r\n    </h1>\r\n    <div class=\"search-box\">\r\n      <!-- Text input -->\r\n      <input\r\n        placeholder=\"Type something to search\"\r\n        type=\"text\"\r\n        class=\"search-box__input\"\r\n      />\r\n\r\n      <!-- Search icon sticks to the left or right -->\r\n      Search Icon\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/search-box"}'), ('"slider"', '"Prsnt"', '"vanilla"', '{"demo.css": ".slider {\n  /* Content is centered horizontally */\n  align-items: center;\n  display: flex;\n\n  /* Size */\n  height: 2rem;\n}\n\n.slider__left {\n  height: 2px;\n\n  /* Colors */\n  background-color: #d1d5db;\n}\n\n.slider__circle {\n  /* Size */\n  height: 2rem;\n  width: 2rem;\n\n  /* Rounded border */\n  border-radius: 9999px;\n\n  /* Colors */\n  background-color: #3b82f6;\n}\n\n.slider__right {\n  /* Take the remaining width */\n  flex: 1;\n  height: 2px;\n\n  /* Colors */\n  background-color: #d1d5db;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"slider\">\r\n      <!-- Left side -->\r\n      <!-- Width based on the current value -->\r\n      <div class=\"slider__left\" style=\"width: 20%;\"></div>\r\n\r\n      <!-- Circle -->\r\n      <div class=\"slider__circle\"></div>\r\n\r\n      <!-- Right side -->\r\n      <div class=\"slider__right\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/slider"}'), ('"spin-button"', '"Prsnt"', '"vanilla"', '{"demo.css": ".spin-button {\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  display: flex;\n  overflow: hidden;\n}\n\n.spin-button__input {\n  border-color: transparent;\n  padding: 0.5rem;\n\n  /* Demo */\n  width: 8rem;\n}\n\n.spin-button__buttons {\n  /* Content is centered vertically */\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n\n  /* Left border */\n  border-left: 1px solid #d1d5db;\n}\n\n.spin-button__button {\n  /* Reset */\n  background: #fff;\n  border-color: transparent;\n  cursor: pointer;\n\n  /* Make buttons have the same height */\n  flex: 1;\n}\n\n/* You can use the triangle buttons to create the up and down buttons: */\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Spin button\r\n    </h1>\r\n    <div class=\"spin-button\">\r\n      <!-- Input -->\r\n      <input type=\"text\" class=\"spin-button__input\" />\r\n\r\n      <!-- Buttons spin-button -->\r\n      <div class=\"spin-button__buttons\">\r\n        <!-- Up button -->\r\n        <button class=\"spin-button__button\">Up</button>\r\n\r\n        <!-- Down button -->\r\n        <button class=\"spin-button__button\">Dwon</button>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/spin-button"}'), ('"stepper-input"', '"Prsnt"', '"vanilla"', '{"demo.css": ".stepper-input {\n  display: flex;\n\n  /* Border */\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n\n  /* Size */\n  height: 2rem;\n}\n\n.stepper-input__button {\n  /* Reset */\n  background: #d1d5db;\n  border: none;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n  justify-content: center;\n\n  /* Size */\n  width: 2rem;\n}\n\n.stepper-input__content {\n  flex: 1;\n}\n\n.stepper-input__input {\n  /* Reset */\n  border: none;\n\n  /* Take full size of its container */\n  height: 100%;\n  width: 100%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Stepper input\r\n    </h1>\r\n    <div class=\"stepper-input\">\r\n      <!-- Minus button -->\r\n      <button class=\"stepper-input__button\">-</button>\r\n\r\n      <!-- Input container -->\r\n      <div class=\"stepper-input__content\">\r\n        <input type=\"text\" class=\"stepper-input__input\" />\r\n      </div>\r\n\r\n      <!-- Plus button -->\r\n      <button class=\"stepper-input__button\">+</button>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/stepper-input"}'), ('"switch"', '"Prsnt"', '"vanilla"', '{"demo.css": ".switch {\n  display: flex;\n\n  /* Rounded border */\n  border-radius: 9999px;\n\n  /* Size */\n  height: 2rem;\n  width: 4rem;\n\n  /* Demo */\n  margin-bottom: 0.5rem;\n}\n\n.switch__input {\n  /* Hide the input */\n  display: none;\n}\n\n.switch__circle {\n  /* Rounded border */\n  border-radius: 9999px;\n\n  /* Size */\n  width: 2rem;\n\n  background-color: #fff;\n}\n\n/* The switch comes with two variants: */\n/* ON status */\n.switch--on {\n  background-color: #357edd;\n  border: 1px solid #357edd;\n\n  /* Push the circle to the right */\n  justify-content: flex-end;\n}\n\n/* OFF status */\n.switch--off {\n  background-color: #d1d5db;\n  border: 1px solid #d1d5db;\n}\n.switch--off .switch__circle {\n  border: 1px solid #d1d5db;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Switch\r\n    </h1>\r\n    <label class=\"switch switch--on\">\r\n      <input type=\"checkbox\" class=\"switch__input\" />\r\n\r\n      <!-- Circle -->\r\n      <div class=\"switch__circle\"></div>\r\n    </label>\r\n\r\n    <label class=\"switch switch--off\">\r\n      <input type=\"checkbox\" class=\"switch__input\" />\r\n\r\n      <!-- Circle -->\r\n      <div class=\"switch__circle\"></div>\r\n    </label>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/switch"}'), ('"toggle-password-visibility"', '"Prsnt"', '"vanilla"', '{"demo.css": ".toggle-password-visibility {\n  display: flex;\n\n  /* Border */\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  padding: 0.25rem;\n}\n\n.toggle-password-visibility__input {\n  border-color: transparent;\n\n  /* Take available width */\n  flex: 1;\n}\n\n.toggle-password-visibility__toggle {\n  /* Reset */\n  background: #fff;\n  border-color: transparent;\n\n  /* Center the content */\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n/* \nIn reality, the click event handler of the button needs to update the type attribute of the input to text or password:\n\ndocument.querySelector(''.toggle-password-visibility__toggle'').addEventListener(''click'', (e) => {\n    const input = e.target.previousElementSibling;\n    const type = input.getAttribute(''type'');\n    input.setAttribute(''type'', type === ''text'' ? ''password'' : ''text'');\n}); \n*/\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Toggle password visibility\r\n    </h1>\r\n    <div class=\"toggle-password-visibility\">\r\n      <!-- Text input -->\r\n      <input\r\n        placeholder=\"password\"\r\n        type=\"password\"\r\n        class=\"toggle-password-visibility__input\"\r\n      />\r\n\r\n      <!-- Toggle button sticks to the right -->\r\n      <button class=\"toggle-password-visibility__toggle\">\r\n        Toggle Button(Eye)\r\n      </button>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/toggle-password-visibility"}'), ('"upload-button"', '"Prsnt"', '"vanilla"', '{"demo.css": ".upload-button {\n  /* Used to position the input */\n  position: relative;\n\n  /* Center the content */\n  align-items: center;\n  display: flex;\n\n  /* Border */\n  border: 1px solid #d1d5db;\n  border-radius: 0.25rem;\n  padding: 0.25rem 0.5rem;\n}\n\n.upload-button__input {\n  /* Take the full size */\n  height: 100%;\n  left: 0;\n  position: absolute;\n  top: 0;\n  width: 100%;\n\n  /* Make it transparent */\n  opacity: 0;\n}\n\n.upload-button__icon {\n  margin-right: 0.5rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Upload Button</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"upload-button\">\r\n      <!-- The real file input -->\r\n      <input type=\"file\" class=\"upload-button__input\" />\r\n\r\n      <!-- The upload icon -->\r\n      <div class=\"upload-button__icon\">Upload Icon</div>\r\n\r\n      <!-- The label -->\r\n      Label Here\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Input/upload-button"}'), ('"3-tile-layout"', '"Prsnt"', '"vanilla"', '{"demo.css": ".tiles {\n  width: 600px;\n  font-size: 0;\n  margin: 0 auto;\n}\n\n.tile {\n  width: calc(600px / 3);\n  display: inline-block;\n}\n\n.tile h2 {\n  font-size: 20px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      3-tile layout\r\n    </h1>\r\n    <div class=\"tiles\">\r\n      <div class=\"tile\">\r\n        <img src=\"https://via.placeholder.com/200x150\" />\r\n        <h2>30 Seconds of CSS</h2>\r\n      </div>\r\n      <div class=\"tile\">\r\n        <img src=\"https://via.placeholder.com/200x150\" />\r\n        <h2>30 Seconds of CSS</h2>\r\n      </div>\r\n      <div class=\"tile\">\r\n        <img src=\"https://via.placeholder.com/200x150\" />\r\n        <h2>30 Seconds of CSS</h2>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/3-tile-layout"}'), ('"aspect-ratio"', '"Prsnt"', '"vanilla"', '{"demo.css": ".container {\n  --aspect-ratio: 16/9;\n  position: relative;\n  height: 0;\n  padding-bottom: calc(100% / (var(--aspect-ratio)));\n}\n\n.container > * {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  object-fit: cover;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Aspect ratio\r\n    </h1>\r\n    <div class=\"container\">\r\n      <img src=\"https://picsum.photos/id/119/800/450\" />\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/aspect-ratio"}'), ('"box-sizing-reset"', '"Prsnt"', '"vanilla"', '{"demo.css": "div {\n  box-sizing: border-box;\n}\n\n*,\n*::before,\n*::after {\n  box-sizing: inherit;\n}\n\n.box {\n  display: inline-block;\n  width: 120px;\n  height: 120px;\n  padding: 8px;\n  margin: 8px;\n  background: #F24333;\n  color: white;\n  border: 1px solid #BA1B1D;\n  border-radius: 4px;\n}\n\n.content-box {\n  box-sizing: content-box;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Box-sizing reset\r\n    </h1>\r\n    <div class=\"box\">border-box</div>\r\n    <div class=\"box content-box\">content-box</div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/box-sizing-reset"}'), ('"card-layout"', '"Prsnt"', '"vanilla"', '{"demo.css": ".card-layout {\n  display: flex;\n\n  /* Put a card in the next row when previous cards take all width */\n  flex-wrap: wrap;\n\n  margin-left: -0.25rem;\n  margin-right: -0.25rem;\n}\n\n.card-layout__item {\n  /* There will be 3 cards per row */\n  flex-basis: 33.33333%;\n\n  padding-left: 0.25rem;\n  padding-right: 0.25rem;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Card Layout\r\n    </h1>\r\n    <div class=\"card-layout\">\r\n      <!-- A card with given width -->\r\n      <div class=\"card-layout__item\">...</div>\r\n\r\n      <!-- Repeat other cards -->\r\n      ...\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/card-layout"}');